            "Qualification": 25,
            "Proposal": 60,
            "Closed-Won": 100,
            "Closed-Lost": 0
          }
        }
      ]
    }
  ],
  "navigation": [
    {
      "label": "Accounts",
      "icon": "building",
      "view": "account_table"
