      "view": "contact_table"
    },
    {
      "label": "Pipeline",
      "icon": "chart-line",
      "view": "deal_pipeline"
    },
    {
      "label": "Dashboard",
      "icon": "dashboard",
      "view": "pipeline_dashboard"
    }
  ]
}
